module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output reg carry,
    output negative,
    output reg overflow,
    output flag
);


    reg [63:0] res;
    reg slt_flag;
    reg sltu_flag;

    assign r = res[31:0];
    assign zero = |res[31:0];
    assign negative = res[31];
    assign flag = (aluc == SLT || aluc == SLTU) ? slt_flag && sltu_flag : 1'b0;

    always @(*) begin
        slt_flag = 1'b0;
        sltu_flag = 1'b0;
        carry = 1'b0;
        overflow = 1'b0;
        case (aluc)
            ADD: begin
                {carry, res} = {a[31], a} + {b[31], b};
                overflow = carry ^ res[31];
            end
            ADDU: begin
                {carry, res} = {1'b0, a} + {1'b0, b};
                overflow = carry;
            end
            SUB: begin
                {carry, res} = {a[31], a} - {b[31], b};
                overflow = carry ^ res[31];
            end
            SUBU: begin
                {carry, res} = {1'b0, a} - {1'b0, b};
                overflow = carry;
            end
            AND: res = {16'b0, a & b};
            OR: res = {16'b0, a | b};
            XOR: res = {16'b0, a ^ b};
            NOR: res = {16'b0, ~(a | b)};
            SLT: begin
                res = {b[31] ^ a[31], 31'b0};
                slt_flag = (a[31] ^ b[31]) ? ~a[31] : res[32];
            end
            SLTU: begin
                res = {1'b0, a < b};
                sltu_flag = ~res[32];
            end
            SLL: res = {b << a[4:0]};
            SRL: res = {b >> a[4:0]};
            SRA: res = {b[31], b[31:1]};
            SLLV: res = {b << a[4:0]};
            SRLV: res = {b >> a[4:0]};
            SRAV: res = {b[31], b[31:1]};
            LUI: res = {b[15:0], 16'b0};
            default: res = 64'b0;
        endcase
    end
endmodule
